// And groups predicates with the AND operator between them.
func And(predicates ...predicate.BusinessRecord) predicate.BusinessRecord {
	return predicate.BusinessRecord(sql.AndPredicates(predicates...))
}

// Or groups predicates with the OR operator between them.
func Or(predicates ...predicate.BusinessRecord) predicate.BusinessRecord {
	return predicate.BusinessRecord(sql.OrPredicates(predicates...))
}

// Not applies the not operator on the given predicate.
func Not(p predicate.BusinessRecord) predicate.BusinessRecord {
	return predicate.BusinessRecord(sql.NotPredicates(p))
}
